SELECT ?year ?rq_paper_count ?rqa_paper_count ?more_reported
WHERE {

    {
      SELECT ?year (COUNT(DISTINCT ?paper) AS ?rq_paper_count)
      WHERE {
        ?paper orkgp:P31 ?contribution ;
              orkgp:P29 ?year .

        ?contribution a orkgc:C27001 ;
                      orkgp:P135046 ?venue ;
                      orkgp:P37330 ?research_question .

        ?venue rdfs:label ?venue_name .

        FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
      }
      GROUP BY ?year
    }

    {
      SELECT ?year (COUNT(DISTINCT ?paper) AS ?rqa_paper_count)
      WHERE {
        ?paper orkgp:P31 ?contribution ;
              orkgp:P29 ?year .

        ?contribution a orkgc:C27001 ;
                      orkgp:P135046 ?venue ;
                      orkgp:P57004 ?research_question_answer .

        ?venue rdfs:label ?venue_name .

        FILTER(?venue_name = "IEEE International Requirements Engineering Conference"^^xsd:string)
      }
      GROUP BY ?year
    }

    BIND(
      IF(?rq_paper_count > ?rqa_paper_count, "research question",
        IF(?rqa_paper_count > ?rq_paper_count, "research question answer", "tie")
      ) AS ?more_reported
    )
}
ORDER BY ?year

